import numpy as np

def xavier_uniform(fan_in: int, fan_out: int) -> np.ndarray:
    limit = np.sqrt(6 / (fan_in + fan_out))
    return np.random.uniform(-limit, limit, size=(fan_in, fan_out))

def xavier_normal(fan_in: int, fan_out: int) -> np.ndarray:
    std = np.sqrt(2 / (fan_in + fan_out))
    return np.random.randn(fan_in, fan_out) * std

def init_mlp_xavier(layer_sizes: list[int], mode: str = 'uniform') -> list[tuple]:
    params = []
    for i in range(len(layer_sizes) - 1):
        fan_in = layer_sizes[i]
        fan_out = layer_sizes[i + 1]
        if mode == 'uniform':
            W = xavier_uniform(fan_in, fan_out)
        elif mode == 'normal':
            W = xavier_normal(fan_in, fan_out)
        else:
            raise ValueError(f"Unknown mode '{mode}'. Use 'uniform' or 'normal'.")
        b = np.zeros(fan_out)
        params.append((W, b))
    return params

